import sys

def calc_column_averages(csv_path):
    with open(csv_path, 'r') as f:
        reader = csv.reader(f)
        headers = next(reader)
        col_sums = [0.0] * len(headers)
        col_counts = [0] * len(headers)
        for row in reader:
            for i, val in enumerate(row):
                try:
                    col_sums[i] += float(val)
                    col_counts[i] += 1
                except ValueError:
                    pass
    averages = [s / c if c > 0 else 0 for s, c in zip(col_sums, col_counts)]
    return headers, averages

if __name__ == '__main__':
    if len(sys.argv) < 2:
        print('Usage: python calc_avg.py <csv_path>')
        sys.exit(1)
    headers, avgs = calc_column_averages(sys.argv[1])
    with open('result.txt', 'w') as f:
        for h, a in zip(headers, avgs):
            f.write(f'{h}: {a:.2f}\n')
